// Input: { seed_post: '...', lang?: 'en', platforms?: ['twitter','mastodon','reddit'], reddit_subs?: [...] }
const body = $input.first().json.body || $input.first().json;
const seed = body.seed_post || '';
const lang = body.lang || 'en';
const platformsAll = ['twitter','mastodon','reddit','indiehackers','devto','linkedin'];
const platforms = Array.isArray(body.platforms) && body.platforms.length ? body.platforms : platformsAll;
const reddit_subs = body.reddit_subs || [];
if (!seed || seed.length < 30) return [{ json: { error: 'seed_post required (min 30 chars)' }}];
return platforms.map(p => ({ json: { seed, lang, platform: p, reddit_subs }}));

