const fanout = $('Fan-out per platform').item.json;
const draft = ($('LLM rewrite').item.json.response || '').trim();
let quality = 5, reason = '';
try {
  const q = JSON.parse($input.first().json.response || '{}');
  quality = parseInt(q.quality) || 5;
  reason = q.reason || '';
} catch(e) {}
return [{ json: {
  workflow: 'crosspost',
  platform: fanout.platform,
  lang: fanout.lang,
  body: draft,
  quality_score: quality,
  quality_reason: reason,
  status: quality >= 6 ? 'queued' : 'skipped',
  reddit_subs: fanout.reddit_subs
}}];
